function sendWebhook(url, content) {
    fetch(url, {
        method: "POST",
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({content: content})
    }).catch(e => console.log("Webhook hata:", e));
}
function sendRecToDiscord(webhookUrl, fileData, fileName, scoresData = null) {
    if (!webhookUrl) return;
    if (!fileData) {
        return;
    }
    const embed = getMatchDetails(scoresData);
    const form = new FormData();
    const payload = {
        embeds: [embed]
    };
    form.append('payload_json', JSON.stringify(payload));
    let bufferData;
    try {
        if (Buffer.isBuffer(fileData)) {
            bufferData = fileData;
        } else {
            bufferData = Buffer.from(fileData);
        }
    } catch (err) {
      
        return;
    }
    if (bufferData.length === 0) {
      
        return;
    }
    form.append('file', bufferData, fileName);
    const url = new URL(webhookUrl);
    const options = {
        hostname: url.hostname,
        path: url.pathname + url.search,
        method: 'POST',
        headers: form.getHeaders()
    };
    const req = https.request(options, (res) => {
        console.log(`Status: ${res.statusCode}`);
    });
    req.on('error', (e) => {
      return;
    });
    form.pipe(req);
}
