function kısıtlataç(oyuncu) {
    let playerscGroup = room.getPlayerDiscProperties(oyuncu.id).cGroup;
    room.setPlayerDiscProperties(oyuncu.id, {cGroup: playerscGroup | room.CollisionFlags.c0})
}
function kısıtlamayıkaldırtaç(oyuncu) {
    let playerscGroup = room.getPlayerDiscProperties(oyuncu.id).cGroup;
    if((playerscGroup & room.CollisionFlags.c0) !== 0) {
        room.setPlayerDiscProperties(oyuncu.id, {cGroup: playerscGroup - room.CollisionFlags.c0})
    }
}
function kısıtlaaut(oyuncu) {
    let playerscGroup = room.getPlayerDiscProperties(oyuncu.id).cGroup;
    room.setPlayerDiscProperties(oyuncu.id, {cGroup: playerscGroup | room.CollisionFlags.c2})
}
