function oyuncuMevkiyeAta() {
    const takimlar = [
        { obj: mevkilerred, isRed: true },
        { obj: mevkilerblue, isRed: false }
    ];

    const koordinatlarRed = {
        gk:   { x:-1380, y:0 },
        dm3:  { x:-1000, y:0 },
        dm6:  { x:-750, y:0 },
        os:   { x:-550, y:-200 },
        fv10: { x:-500, y:280 },
        fv9:  { x:-250, y:0 }
    };

    const koordinatlarBlue = {
        gk:   { x:1380, y:0 },
        dm3:  { x:1000, y:0 },
        dm6:  { x:750, y:0 },
        os:   { x:550, y:-200 },
        fv10: { x:500, y:280 },
        fv9:  { x:250, y:0 }
    };

    const mevkiIsimleri = {
        gk: "Kaleci",
        dm3: "Defans",
        dm6: "Defans",
        os: "Ofansif Orta Saha",
        fv10: "Forvet",
        fv9: "Forvet"
    };

    const mevkiNumaralari = {
        gk: 1,
        dm3: 3,
        dm6: 6,
        os: 8,
        fv10: 10,
        fv9: 9
    };

    for(const takim of takimlar) {
        const mevkiler = takim.obj;
        const coords = takim.isRed ? koordinatlarRed : koordinatlarBlue;

        for(const key in mevkiler) {
            const oyuncu = mevkiler[key];
            if(oyuncu.name !== null) {
                const pos = coords[key];
                room.setPlayerDiscProperties(oyuncu.id, { x: pos.x, y: pos.y, xspeed: 0, yspeed: 0 });

         
                const mesaj = `Bu maçta ${mevkiNumaralari[key]} / ${mevkiIsimleri[key]} mevkiinde oynuyorsun.`;
                room.sendAnnouncement(mesaj, oyuncu.id, 0xFFFFFF, "bold");
            }
        }
    }
}

