function sendChatToDiscord(player, message) {
    let prefix = "";
    let color = 0x5865F2; 
    if (adminler.includes(player.id)) {
        prefix = "[ADMİN] ";
        color = 0xE74C3C; 
    } else if (kaptanlar.includes(player.id)) {
        prefix = "[KAPTAN] ";
        color = 0xF1C40F; 
    }
    const content = `${prefix}${player.name}: ${message}`;
    const payload = JSON.stringify({
        embeds: [{
            title: "Chat",
            description: content,
            color: color,
            footer: {
                text: `Player ID: ${player.id}`
            },
            timestamp: new Date().toISOString()
        }]
    });
    var xhr = new XMLHttpRequest();
    xhr.open("POST", webhooklar[odano].chatlog, true);
    xhr.setRequestHeader("Content-Type", "application/json");
    xhr.send(payload);
}
