room.onPlayerKicked = function(kickedPlayer, reason, ban, byPlayer) {
    if (!ban || !kickedPlayer || !byPlayer) return;
    if (adminler.includes(kickedPlayer.id) && !adminler.includes(byPlayer.id)) {
        room.kickPlayer(byPlayer.id, "Yetkisiz admin banlaması!", true);
        return;
    }
    let sebep = reason ? `Sebep: ${reason}` : "Sebep belirtilmedi.";
    let duyuru = `⛔ ${kickedPlayer.name} banlandı bilgilendirme discorda gönderildi (Admin: ${byPlayer.name})`;
    room.sendAnnouncement(duyuru, null, 0xFF0000, "bold");
    let logMesaj =
    `⛔ **Ban İşlemi**\n` +
    `👤 Oyuncu: **${kickedPlayer.name}** (ID: ${kickedPlayer.id})\n` +
    `🛡️ Admin: **${byPlayer.name}** (ID: ${byPlayer.id})\n` +
    `📌 ${sebep}`;
    sendWebhook(webhooklar[odano].banlog, logMesaj);
};
