room.onGameStop = function(byPlayer) {
    if (isRecording) {
        isRecording = false;
        rsMatchActive = false;
        const finalScores = macSkoruCache || room.getScores();
        const replay = room.stopRecording();
        if (replay && replay.length > 0) {
            const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
            const fileName = `-Mac-${odano}-${timestamp}.hbr2`;
            const webhookUrl = webhooklar[odano]?.reclog || webhooklar[odano]?.chatlog;
            if (webhookUrl) {
                sendRecToDiscord(webhookUrl, replay, fileName, finalScores);
            } else {
               return;
            }
        } else {
            return;
        }
    }
};
