function formatTime(time){
    let dakika = Math.floor(time / 60);
    let saniye = Math.floor(time % 60);
    return `${dakika}:${saniye < 10 ? "0" + saniye : saniye}`;
}
room.onTeamGoal = function(team) {
    if(!lastTouch) return;
    let scores = room.getScores();
    let timeFormatted = formatTime(scores.time);
    let scorer = lastTouch;
    let assist = (secondLastTouch && secondLastTouch.team == team) ? secondLastTouch : null;
    if(scorer.team == team){
        if(assist){
            room.sendAnnouncement(`🥅 Gol: ${scorer.name} ⚽, 🎯 Asist: ${assist.name}, ⌛ Süre: ${timeFormatted}`);
        }else{
            room.sendAnnouncement(`🥅 Gol: ${scorer.name} ⚽, ⌛ Süre: ${timeFormatted}`);
        }
    }else{
        room.sendAnnouncement(`😔 KK Gol: ${scorer.name}, ⌛ Süre: ${timeFormatted}`);
    }
    lastTouch = null;
    secondLastTouch = null;
};
